code = """import json
import re

stockinfo = locals()['var_function-call-2611435032993544713']
avg_vol_res = locals()['var_function-call-1189212217820151430']

# Create a map of Symbol -> Company Description
symbol_desc_map = {item['Symbol']: item['Company Description'] for item in stockinfo}

final_results = []
for item in avg_vol_res:
    sym = item['Symbol']
    vol = item['AvgVolume']
    if vol != 'nan' and vol is not None:
        try:
            vol_float = float(vol)
            if vol_float > 0:
                desc = symbol_desc_map.get(sym, "Unknown")
                
                # Heuristic to extract name
                # Most descriptions are "Name specializes/is/provides/..."
                # Split by common verbs/phrases
                splitters = [' specializes', ' is', ' provides', ' offers', ' harnesses', ' dedicated', ' based', ' focuses', ' engages', ' operates', ' aims', ' strives']
                name = desc
                for splitter in splitters:
                    if splitter in name:
                        name = name.split(splitter)[0]
                        break
                
                name = name.strip(' .,')
                final_results.append({"Company Name": name, "Average Volume 2008": vol_float})
        except ValueError:
            pass

print("__RESULT__:")
print(json.dumps(final_results))"""

